scwin.onpageload = function () {
  //전역변수값 셋팅함수.
  scwin.initSetVal();

  //그리드 컬럼에 공통코드셋팅처리. 
  const codeOptions = [{
    grpCd: "FI019",
    compID: "gr_master:accountPchsSellClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.f_OnLoad);

  //dataMap 생성으로 대체.
  //scwin.f_SearchHeaderCreate();
};
scwin.initSetVal = function () {
  scwin.memJson = $c.data.getMemInfo($p);
  scwin.vLoginCoCd = $c.gus.cfIsNull($p, scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
  scwin.vLoginCoClsCd = $c.gus.cfIsNull($p, scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; //회계_회사구분('CO035' : 0:동부 EXPRESS)
  scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd; // 사용자소속구분코드 
  scwin.vCoCd = $c.gus.cfIsNull($p, scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 회사코드
  scwin.isSubCompany = false;
  scwin.sDate = WebSquare.date.getCurrentServerDate().substring(0, 6);
};

//udc 컴포넌트 onload 완료시...
scwin.onUdcCompleted = function () {
  $c.gus.cfDisableKey($p);
  scwin.f_FieldClear();

  //gr_master.TitleHeight = 30;
  scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  //$c.gus.cfInitObjects(grp_search,[ica_srchCloseYm]);
  $c.gus.cfInitObjects($p, [ica_srchCloseYm]);
  scwin.f_SetSrchDefault();
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
  //$c.gus.cfInitHidVal(grp_search);
  ica_srchCloseYm.setValue(scwin.sDate);
  ica_srchCloseYm.focus();
};

//udc 컴포넌트의 돋보기 버튼 클릭시
scwin.udc_comCode1_onclickEvent = async function (e) {
  await scwin.f_PopUpCompanyInfo('T');
};

//udc 컴포넌트의 코드측 포커스 아웃시
scwin.udc_comCode1_onblurCodeEvent = async function (e) {
  ed_coNm.setValue("");
  if (ed_coCd.getValue() != "") {
    await scwin.f_PopUpCompanyInfo('T');
  }
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = async function () {
  //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
  if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
    scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
    scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
  }
  ed_coCd.setValue(scwin.vLoginCoCd);
  await scwin.f_PopUpCompanyInfo('T');
  $c.gus.cfDisableObjects($p, [ed_coCd, ed_coNm, btn_company]);
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
  udc_comCode1.setSelectId("retrieveDongbuGroupCompanyInfo");
  await udc_comCode1.cfCommonPopUp(scwin.udc_comCode1_callBackFunc, ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF, null, null, null, null, null, null, null, null, null);
};
scwin.udc_comCode1_callBackFunc = function (rtnList) {
  // SET
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }
    ed_coCd.setValue(rtnList[0]); // 코드
    ed_coNm.setValue(rtnList[5]); // 회사명
  } else {
    ed_coCd.setValue(""); // 코드
    ed_coNm.setValue(""); // 회사명
  }
  if (ed_coCd.getValue() > ACConstants.CO_CD_DONGBU) {
    // 자회사 회계 시스템 
    scwin.isSubCompany = true;
  } else {
    scwin.isSubCompany = false;
  }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
  let ret = await $c.gus.cfValidate($p, [ica_srchCloseYm]);
  if (!ret) {
    return false;
  }

  //ds_search.UseChangeInfo = false;
  //tr_search.post();
  dma_search.set("closeYm", ica_srchCloseYm.getValue());
  dma_search.set("acctDeptCd", "");
  dma_search.set("pchsSellClsCd", "");
  dma_search.set("branchYn", 0);
  dma_search.set("coCd", ed_coCd.getValue());

  //submit 처리.
  let searchSubmit = await $c.sbm.execute($p, sbm_search);
  if (searchSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_search_submitdone();
  }
};
scwin.sbm_search_submitdone = async function (e) {
  if (ds_master.getRowCount() > 0) {
    //subsum row 갯수 + footer row 갯수
    var nTotalCnt = gr_master.getSubtotalRowList().length + 1;

    //totalRows.setValue(ds_master.getRowCount()+nTotalCnt);
    totalRows.setValue(ds_master.getRowCount());

    //미확정내역 DataSet
    //name=SortExpr value="+branchNm+accountPchsSellClsCd" 
    var options = {};
    options.sortIndex = "branchNm accountPchsSellClsCd";
    options.sortOrder = "1 1"; //오른차순:"1", 내림차순"-1"
    ds_master.multisort(options);
    ds_master.reform();
  } else {
    totalRows.setValue(0);
  }
  if (ds_master.getRowCount() == 0) {
    if ($c.gus.cfCheckCreateFlag($p) == true) {
      $c.gus.cfTurnCreateFlag($p, false);
    } else {
      await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    }
    $c.gus.cfDisableObjects($p, [btn_save]);
  } else {
    if ($c.gus.cfIsNull($p, ds_master.getCellData(1, "slipNo"))) {
      $c.gus.cfEnableObjects($p, [btn_save]);
    } else {
      $c.gus.cfDisableObjects($p, [btn_save]);
    }

    //gr_master.focus();
  }
};

