//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (ds_master.getRowCount() < 1) {
    await $c.gus.cfAlertMsg($p, "조회된 자료가 없습니다.");
  } else {
    let ret = await $c.gus.cfValidate($p, [ica_srchCloseYm]);
    if (!ret) {
      return false;
    }
    let confirmResult = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (confirmResult) {
      //ds_master.UseChangeInfo = false;
      //tr_master.post();

      //submit 처리.
      let masterSubmit = await $c.sbm.execute($p, sbm_master);
      if (masterSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_master_submitdone();
      }
    }
  }
};
scwin.sbm_master_submitdone = async function (e) {
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
  await scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Export = async function () {
  let confirmResult = await $c.win.confirm($p, "Excel로 다운로드 하시겠습니까?");
  if (confirmResult) {
    var exportFileName = "미확정실적 회계전표생성_" + ica_srchCloseYm.getValue().trim() + ".xlsx";

    //to-do
    //gr_master.ColumnProp("num","show") = false;
    //to-do
    //gr_master.ColumnProp("month","show") = false;
    gr_master.ViewSummary = "0";

    //cfGridToExcel(objGridName, "미확정실적 회계전표생성",exportFileName,8+16);
    const options = {
      fileName: exportFileName,
      sheetName: "미확정실적 회계전표생성",
      colMerge: true,
      colMergeTextAlign: "top",
      useSubTotal: true,
      //to-do 공통함수 미적용됨.
      useFooter: false
    };
    $c.data.downloadGridViewExcel($p, gr_master, options);

    //to-do
    //gr_master.ColumnProp("num","show") = true;
    //to-do
    //gr_master.ColumnProp("month","show") = true;
    gr_master.ViewSummary = "1";
  }
};

